'use strict';

const os = require('node:os');
const path = require('node:path');
const fs = require('node:fs');

const DATA_DIR = process.env.TODO_DIR || path.join(os.homedir(), '.todo-cli');
const DATA_FILE = path.join(DATA_DIR, 'todos.json');

function load() {
  try {
    const raw = fs.readFileSync(DATA_FILE, 'utf8');
    const data = JSON.parse(raw);
    if (!Array.isArray(data.todos)) return { todos: [], nextId: 1 };
    return { todos: data.todos, nextId: data.nextId || data.todos.length + 1 };
  } catch (err) {
    if (err.code === 'ENOENT') return { todos: [], nextId: 1 };
    throw err;
  }
}

function save(state) {
  fs.mkdirSync(DATA_DIR, { recursive: true });
  fs.writeFileSync(DATA_FILE, JSON.stringify(state, null, 2), 'utf8');
}

module.exports = { load, save, DATA_FILE };

