'use strict';

const { load, save } = require('./store');

function add(text) {
  if (!text || !text.trim()) {
    throw new Error('待办内容不能为空');
  }
  const state = load();
  const todo = {
    id: state.nextId,
    text: text.trim(),
    done: false,
    createdAt: new Date().toISOString(),
  };
  state.todos.push(todo);
  state.nextId += 1;
  save(state);
  return todo;
}

function findIndex(state, id) {
  const idx = state.todos.findIndex((t) => t.id === id);
  if (idx === -1) throw new Error(`找不到编号为 ${id} 的待办事项`);
  return idx;
}

function setDone(id, done) {
  const state = load();
  const idx = findIndex(state, id);
  state.todos[idx].done = done;
  save(state);
  return state.todos[idx];
}

function remove(id) {
  const state = load();
  const idx = findIndex(state, id);
  const [removed] = state.todos.splice(idx, 1);
  save(state);
  return removed;
}

function clearDone() {
  const state = load();
  const before = state.todos.length;
  state.todos = state.todos.filter((t) => !t.done);
  save(state);
  return before - state.todos.length;
}

function list(filter) {
  const state = load();
  if (filter === 'pending') return state.todos.filter((t) => !t.done);
  if (filter === 'done') return state.todos.filter((t) => t.done);
  return state.todos;
}

module.exports = { add, setDone, remove, clearDone, list };

