#!/usr/bin/env node
'use strict';

const cmds = require('../src/commands');

const HELP = `Todo CLI — 简单的命令行待办事项管理

用法:
  todo add <内容>        新增一条待办
  todo list [--pending|--done]
                         列出待办
  todo done <id>         标记为已完成
  todo undone <id>       标记为未完成
  todo remove <id>       删除待办
  todo clear             清空所有已完成的待办
`;

function parseId(raw) {
  const id = Number.parseInt(raw, 10);
  if (!Number.isInteger(id)) {
    throw new Error(`无效的编号: ${raw}`);
  }
  return id;
}

function renderList(todos) {
  if (todos.length === 0) {
    console.log('暂无待办事项');
    return;
  }
  for (const t of todos) {
    const mark = t.done ? '[x]' : '[ ]';
    console.log(`${String(t.id).padStart(3)} ${mark} ${t.text}`);
  }
}

function main(argv) {
  const [command, ...rest] = argv;

  switch (command) {
    case 'add': {
      const todo = cmds.add(rest.join(' '));
      console.log(`已添加 #${todo.id}: ${todo.text}`);
      break;
    }
    case 'list': {
      let filter;
      if (rest.includes('--pending')) filter = 'pending';
      else if (rest.includes('--done')) filter = 'done';
      renderList(cmds.list(filter));
      break;
    }
    case 'done': {
      const todo = cmds.setDone(parseId(rest[0]), true);
      console.log(`已完成 #${todo.id}: ${todo.text}`);
      break;
    }
    case 'undone': {
      const todo = cmds.setDone(parseId(rest[0]), false);
      console.log(`已还原 #${todo.id}: ${todo.text}`);
      break;
    }
    case 'remove': {
      const todo = cmds.remove(parseId(rest[0]));
      console.log(`已删除 #${todo.id}: ${todo.text}`);
      break;
    }
    case 'clear': {
      const n = cmds.clearDone();
      console.log(`已清除 ${n} 条已完成事项`);
      break;
    }
    case 'help':
    case '--help':
    case undefined:
      console.log(HELP);
      break;
    default:
      throw new Error(`未知命令: ${command}\n运行 "todo help" 查看用法`);
  }
}

try {
  main(process.argv.slice(2));
} catch (err) {
  console.error(`错误: ${err.message}`);
  process.exit(1);
}

