'use strict';

const { test } = require('node:test');
const assert = require('node:assert');
const os = require('node:os');
const path = require('node:path');
const fs = require('node:fs');

// Isolate storage to a temp dir before loading the modules.
const tmp = fs.mkdtempSync(path.join(os.tmpdir(), 'todo-test-'));
process.env.TODO_DIR = tmp;

const cmds = require('../src/commands');

test('add then list shows the item as pending', () => {
  const todo = cmds.add('买牛奶');
  assert.strictEqual(todo.done, false);
  const all = cmds.list();
  assert.ok(all.find((t) => t.id === todo.id && t.text === '买牛奶'));
});

test('done and undone toggle status', () => {
  const todo = cmds.add('写代码');
  cmds.setDone(todo.id, true);
  assert.strictEqual(cmds.list().find((t) => t.id === todo.id).done, true);
  cmds.setDone(todo.id, false);
  assert.strictEqual(cmds.list().find((t) => t.id === todo.id).done, false);
});

test('remove deletes the item', () => {
  const todo = cmds.add('待删除');
  cmds.remove(todo.id);
  assert.strictEqual(cmds.list().find((t) => t.id === todo.id), undefined);
});

test('clear removes only completed items', () => {
  const a = cmds.add('已完成项');
  const b = cmds.add('未完成项');
  cmds.setDone(a.id, true);
  const cleared = cmds.clearDone();
  assert.ok(cleared >= 1);
  assert.strictEqual(cmds.list().find((t) => t.id === a.id), undefined);
  assert.ok(cmds.list().find((t) => t.id === b.id));
});

test('empty text throws', () => {
  assert.throws(() => cmds.add('   '), /不能为空/);
});

test('invalid id throws', () => {
  assert.throws(() => cmds.remove(99999), /找不到/);
});

